import os
import json
import pymysql
from flask import jsonify

# Connection configuration from environment variables
DB_USER = os.environ.get('DB_USER')
DB_PASS = os.environ.get('DB_PASS')
DB_NAME = os.environ.get('DB_NAME')
DB_HOST = os.environ.get('DB_HOST')  # Cloud SQL private IP or use Unix socket
DB_PORT = int(os.environ.get('DB_PORT', 3306))
# For Cloud SQL with Unix socket:
# DB_CONNECTION_NAME = os.environ.get('DB_CONNECTION_NAME')
# UNIX_SOCKET = f'/cloudsql/{DB_CONNECTION_NAME}'

# Whitelist of allowed table names and column names to prevent injection
ALLOWED_TABLES = {'products', 'customers', 'orders', 'inventory'}

ALLOWED_COLUMNS = {
    'products': {'id', 'name', 'category', 'price', 'status', 'created_at', 'description', 'brand'},
    'customers': {'id', 'name', 'email', 'city', 'state', 'country', 'created_at'},
    'orders': {'id', 'customer_id', 'product_id', 'quantity', 'total', 'status', 'order_date'},
    'inventory': {'id', 'product_id', 'warehouse', 'quantity', 'last_updated'},
}

ALLOWED_SORT_DIRECTIONS = {'ASC', 'DESC'}

ALLOWED_OPERATORS = {
    'eq': '=',
    'neq': '!=',
    'gt': '>',
    'gte': '>=',
    'lt': '<',
    'lte': '<=',
    'like': 'LIKE',
    'in': 'IN',
}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def get_db_connection():
    """Create a database connection using pymysql."""
    connection_params = {
        'user': DB_USER,
        'password': DB_PASS,
        'database': DB_NAME,
        'charset': 'utf8mb4',
        'cursorclass': pymysql.cursors.DictCursor,
        'connect_timeout': 10,
        'read_timeout': 30,
    }

    # Use Unix socket for Cloud SQL (recommended)
    db_connection_name = os.environ.get('DB_CONNECTION_NAME')
    if db_connection_name:
        connection_params['unix_socket'] = f'/cloudsql/{db_connection_name}'
    else:
        connection_params['host'] = DB_HOST
        connection_params['port'] = DB_PORT

    return pymysql.connect(**connection_params)


def validate_table(table_name):
    """Validate table name against whitelist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table: '{table_name}'. Allowed tables: {', '.join(sorted(ALLOWED_TABLES))}")
    return table_name


def validate_column(table_name, column_name):
    """Validate column name against whitelist for the given table."""
    allowed = ALLOWED_COLUMNS.get(table_name, set())
    if column_name not in allowed:
        raise ValueError(
            f"Invalid column: '{column_name}' for table '{table_name}'. "
            f"Allowed columns: {', '.join(sorted(allowed))}"
        )
    return column_name


def validate_operator(operator):
    """Validate operator against whitelist."""
    if operator not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator: '{operator}'. Allowed: {', '.join(sorted(ALLOWED_OPERATORS.keys()))}")
    return ALLOWED_OPERATORS[operator]


def build_dynamic_query(table, filters=None, select_columns=None, sort_by=None,
                        sort_direction='ASC', limit=DEFAULT_LIMIT, offset=0):
    """
    Build a dynamic SQL query using parameterized placeholders.

    SECURITY: Table and column names are validated against whitelists.
    All user-provided VALUES use parameterized queries (%s placeholders).

    Args:
        table: Table name (must be in ALLOWED_TABLES)
        filters: List of dicts with 'column', 'operator', 'value' keys
        select_columns: List of column names to select (None = all allowed columns)
        sort_by: Column name to sort by
        sort_direction: ASC or DESC
        limit: Number of results to return
        offset: Offset for pagination

    Returns:
        Tuple of (query_string, params_list)
    """
    # Validate table
    validated_table = validate_table(table)

    # Build SELECT clause with validated column names
    if select_columns:
        validated_columns = []
        for col in select_columns:
            validated_columns.append(validate_column(validated_table, col))
        # Column names are from whitelist, safe to include directly
        columns_str = ', '.join(f'`{col}`' for col in validated_columns)
    else:
        # Select all allowed columns for the table
        allowed = sorted(ALLOWED_COLUMNS.get(validated_table, set()))
        columns_str = ', '.join(f'`{col}`' for col in allowed)

    # Start building query - table name is validated against whitelist
    query = f"SELECT {columns_str} FROM `{validated_table}`"
    params = []

    # Build WHERE clause using parameterized queries for VALUES
    if filters:
        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f['column'])
            sql_operator = validate_operator(f['operator'])
            value = f['value']

            if f['operator'] == 'in':
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError(f"'in' operator requires a non-empty list of values")
                if len(value) > 100:
                    raise ValueError("'in' operator supports a maximum of 100 values")
                placeholders = ', '.join(['%s'] * len(value))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(value)
            elif f['operator'] == 'like':
                where_clauses.append(f"`{column}` LIKE %s")
                # Escape special LIKE characters in user input, then add wildcards
                safe_value = str(value).replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                params.append(f"%{safe_value}%")
            else:
                where_clauses.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    # Build ORDER BY clause with validated column name
    if sort_by:
        validated_sort_column = validate_column(validated_table, sort_by)
        validated_direction = sort_direction.upper()
        if validated_direction not in ALLOWED_SORT_DIRECTIONS:
            validated_direction = 'ASC'
        query += f" ORDER BY `{validated_sort_column}` {validated_direction}"

    # Apply LIMIT and OFFSET with parameterized values
    validated_limit = min(int(limit), MAX_LIMIT)
    if validated_limit < 1:
        validated_limit = DEFAULT_LIMIT
    validated_offset = max(int(offset), 0)

    query += " LIMIT %s OFFSET %s"
    params.extend([validated_limit, validated_offset])

    return query, params


def build_count_query(table, filters=None):
    """Build a COUNT query for pagination metadata."""
    validated_table = validate_table(table)
    query = f"SELECT COUNT(*) as total FROM `{validated_table}`"
    params = []

    if filters:
        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f['column'])
            sql_operator = validate_operator(f['operator'])
            value = f['value']

            if f['operator'] == 'in':
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError("'in' operator requires a non-empty list of values")
                placeholders = ', '.join(['%s'] * len(value))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(value)
            elif f['operator'] == 'like':
                where_clauses.append(f"`{column}` LIKE %s")
                safe_value = str(value).replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                params.append(f"%{safe_value}%")
            else:
                where_clauses.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    return query, params


def parse_request_params(request):
    """
    Parse HTTP request parameters into structured query components.

    Expected JSON body format:
    {
        "table": "products",
        "select": ["id", "name", "price", "category"],
        "filters": [
            {"column": "category", "operator": "eq", "value": "electronics"},
            {"column": "price", "operator": "lte", "value": 999.99},
            {"column": "status", "operator": "in", "value": ["active", "featured"]},
            {"column": "name", "operator": "like", "value": "laptop"}
        ],
        "sort_by": "price",
        "sort_direction": "DESC",
        "limit": 20,
        "offset": 0,
        "include_count": true
    }

    Or query parameters for simple searches:
    ?table=products&category=electronics&price_lte=999.99&sort_by=price&sort_direction=DESC&limit=20
    """
    if request.is_json:
        data = request.get_json(silent=True) or {}
        return {
            'table': data.get('table'),
            'select_columns': data.get('select'),
            'filters': data.get('filters', []),
            'sort_by': data.get('sort_by'),
            'sort_direction': data.get('sort_direction', 'ASC'),
            'limit': data.get('limit', DEFAULT_LIMIT),
            'offset': data.get('offset', 0),
            'include_count': data.get('include_count', False),
        }
    else:
        # Parse query string parameters for simpler GET requests
        args = request.args
        table = args.get('table')
        if not table:
            raise ValueError("'table' parameter is required")

        filters = []
        allowed_cols = ALLOWED_COLUMNS.get(table, set())

        for key, value in args.items():
            if key in ('table', 'select', 'sort_by', 'sort_direction', 'limit', 'offset', 'include_count'):
                continue

            # Parse column_operator format (e.g., price_lte, name_like)
            parts = key.rsplit('_', 1)
            if len(parts) == 2 and parts[1] in ALLOWED_OPERATORS and parts[0] in allowed_cols:
                column, operator = parts
                # Handle 'in' operator: comma-separated values
                if operator == 'in':
                    value = [v.strip() for v in value.split(',')]
                filters.append({'column': column, 'operator': operator, 'value': value})
            elif key in allowed_cols:
                # Simple equality filter
                filters.append({'column': key, 'operator': 'eq', 'value': value})

        select_raw = args.get('select')
        select_columns = [c.strip() for c in select_raw.split(',')] if select_raw else None

        return {
            'table': table,
            'select_columns': select_columns,
            'filters': filters,
            'sort_by': args.get('sort_by'),
            'sort_direction': args.get('sort_direction', 'ASC'),
            'limit': int(args.get('limit', DEFAULT_LIMIT)),
            'offset': int(args.get('offset', 0)),
            'include_count': args.get('include_count', 'false').lower() == 'true',
        }


def search_api(request):
    """
    Cloud Function entry point for the search API.

    Handles CORS, parses request, builds safe parameterized queries,
    and returns JSON results.
    """
    # Handle CORS preflight
    if request.method == 'OPTIONS':
        headers = {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type, Authorization',
            'Access-Control-Max-Age': '3600',
        }
        return ('', 204, headers)

    cors_headers = {'Access-Control-Allow-Origin': '*'}

    try:
        # Parse request parameters
        params = parse_request_params(request)

        if not params.get('table'):
            return (jsonify({
                'error': "Missing required parameter: 'table'",
                'allowed_tables': sorted(ALLOWED_TABLES),
            }), 400, cors_headers)

        # Build the search query with parameterized placeholders
        query, query_params = build_dynamic_query(
            table=params['table'],
            filters=params.get('filters'),
            select_columns=params.get('select_columns'),
            sort_by=params.get('sort_by'),
            sort_direction=params.get('sort_direction', 'ASC'),
            limit=params.get('limit', DEFAULT_LIMIT),
            offset=params.get('offset', 0),
        )

        connection = get_db_connection()
        try:
            with connection.cursor() as cursor:
                # Execute parameterized query - pymysql handles escaping of params
                cursor.execute(query, query_params)
                results = cursor.fetchall()

                # Convert any non-serializable types (dates, decimals, etc.)
                serialized_results = []
                for row in results:
                    serialized_row = {}
                    for key, value in row.items():
                        if hasattr(value, 'isoformat'):
                            serialized_row[key] = value.isoformat()
                        elif isinstance(value, bytes):
                            serialized_row[key] = value.decode('utf-8', errors='replace')
                        else:
                            serialized_row[key] = value
                    serialized_results.append(serialized_row)

                # Optionally get total count for pagination
                total_count = None
                if params.get('include_count'):
                    count_query, count_params = build_count_query(
                        table=params['table'],
                        filters=params.get('filters'),
                    )
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    total_count = count_result['total'] if count_result else 0

        finally:
            connection.close()

        # Build response
        response_data = {
            'success': True,
            'data': serialized_results,
            'pagination': {
                'limit': min(int(params.get('limit', DEFAULT_LIMIT)), MAX_LIMIT),
                'offset': max(int(params.get('offset', 0)), 0),
                'returned': len(serialized_results),
            },
        }

        if total_count is not None:
            response_data['pagination']['total'] = total_count
            response_data['pagination']['has_more'] = (
                params.get('offset', 0) + len(serialized_results) < total_count
            )

        # Include the query structure (without actual values) for debugging
        # Remove this in production if you don't want to expose query structure
        if os.environ.get('DEBUG_MODE', 'false').lower() == 'true':
            response_data['debug'] = {
                'query_template': query,
                'param_count': len(query_params),
            }

        return (jsonify(response_data), 200, cors_headers)

    except ValueError as e:
        return (jsonify({
            'success': False,
            'error': f'Validation error: {str(e)}',
        }), 400, cors_headers)

    except pymysql.OperationalError as e:
        error_code = e.args[0] if e.args else 'unknown'
        # Don't leak internal database details
        return (jsonify({
            'success': False,
            'error': 'Database connection error. Please try again later.',
            'error_code': 'DB_CONNECTION_ERROR',
        }), 503, cors_headers)

    except pymysql.ProgrammingError as e:
        return (jsonify({
            'success': False,
            'error': 'Invalid query parameters.',
            'error_code': 'QUERY_ERROR',
        }), 400, cors_headers)

    except Exception as e:
        # Log the full error internally but don't expose details
        print(f"Unexpected error: {type(e).__name__}: {str(e)}")
        return (jsonify({
            'success': False,
            'error': 'An internal error occurred.',
            'error_code': 'INTERNAL_ERROR',
        }), 500, cors_headers)